import{_ as e,o as i,c as s,a2 as t}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"Миграция с существующей установки Spatie","description":"","frontmatter":{},"headers":[],"relativePath":"ru/guide/migration.md","filePath":"ru/guide/migration.md"}'),d={name:"ru/guide/migration.md"};function l(c,a,r,o,n,h){return i(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="миграция-с-существующеи-установки-spatie" tabindex="-1">Миграция с существующей установки Spatie <a class="header-anchor" href="#миграция-с-существующеи-установки-spatie" aria-label="Permalink to &quot;Миграция с существующей установки Spatie&quot;">​</a></h1><p>Если ваше приложение уже использует <code>spatie/laravel-permission</code> с существующими ролями, разрешениями и назначениями, <code>clearance:install</code> обнаруживает и сохраняет их - он никогда не запускает миграции Spatie, если таблица <code>roles</code> уже существует. См. <a href="/clearance-docs/ru/guide/installation.html">Установку</a> для полного процесса установки.</p><p>После установки используйте <code>clearance:backfill</code>, чтобы применить собственные метаданные Clearance к вашим существующим ролям и guard&#39;ам.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # meta + role scope + guards</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --only=meta</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # just one section</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # preview, no writes</span></span></code></pre></div><h2 id="что-делает-каждыи-раздел" tabindex="-1">Что делает каждый раздел <a class="header-anchor" href="#что-делает-каждыи-раздел" aria-label="Permalink to &quot;Что делает каждый раздел&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Раздел</th><th>Эффект</th></tr></thead><tbody><tr><td><code>meta</code></td><td>Заполняет отображаемое имя <code>clr_meta</code> (роль в стиле Title Case) для каждой роли, у которой его ещё нет.</td></tr><tr><td><code>roles</code></td><td>Заполняет значения по умолчанию <code>clr_role_meta</code> (<code>scope=global</code>, <code>is_locked=false</code>) для каждой роли, у которой их ещё нет.</td></tr><tr><td><code>guards</code></td><td>Импортирует guard&#39;ы из <code>config(&#39;auth.guards&#39;)</code> в <code>clr_guards</code>, отфильтрованные по <code>allowed_guard_drivers</code>.</td></tr></tbody></table><p>Используйте <code>--only=&lt;section&gt;</code>, чтобы выполнить только один раздел вместо всех трёх.</p><div class="tip custom-block"><p class="custom-block-title">Идемпотентно</p><p>Все разделы идемпотентны - повторный запуск <code>clearance:backfill</code> безопасен и не приведёт к дублированию или перезаписи существующих строк <code>clr_*</code>.</p></div><h2 id="граничные-случаи" tabindex="-1">Граничные случаи <a class="header-anchor" href="#граничные-случаи" aria-label="Permalink to &quot;Граничные случаи&quot;">​</a></h2><p>В репозитории пакета есть более подробное руководство по миграции, охватывающее граничные случаи, не описанные здесь - в частности, что происходит, если в вашей базе данных уже есть роль с именем <code>super_admin</code> (или алиасом вроде <code>superadmin</code>, <code>root</code>, <code>owner</code>), которая конфликтует с собственной ролью <code>super_admin</code> Clearance, а также заметки о пользовательских подклассах моделей <code>Role</code>/<code>Permission</code> и поведении импорта guard&#39;ов. Прочитайте его перед выполнением backfill для продакшн-базы данных с нетривиальными существующими данными о ролях. См. также <a href="/clearance-docs/ru/features/super-admin.html">Super Admin</a> для поведения обнаружения алиасов во время <code>clearance:install</code>.</p><h2 id="смотрите-также" tabindex="-1">Смотрите также <a class="header-anchor" href="#смотрите-также" aria-label="Permalink to &quot;Смотрите также&quot;">​</a></h2><ul><li><a href="/clearance-docs/ru/guide/installation.html">Установка</a> - полный процесс <code>clearance:install</code></li><li><a href="/clearance-docs/ru/api/artisan-commands.html">Команды Artisan</a> - полный справочник команд</li><li><a href="/clearance-docs/ru/guide/architecture.html">Архитектура</a> - таблицы <code>clr_*</code>, которые заполняет backfill</li></ul>`,12)])])}const u=e(d,[["render",l]]);export{k as __pageData,u as default};
